// Combine All Business Dimensions for Postgres JSONB storage
// This consolidates Overview, Contact, Social, Rating, PopularTimes, Tags, Lead Enrichment
// into a single business_data JSONB object

const executionId = $('Store Execution ID').first().json.execution_id;

// IMPORTANT: Replace these node names with YOUR actual node names from ETL pipeline
// These are typical names - adjust based on your workflow
const getNodeData = (nodeName) => {
  try {
    return $input.all().find(item => item.json[nodeName])?.[nodeName] || {};
  } catch {
    return {};
  }
};

// Process all items from merged ETL output
const results = [];

for (const item of $input.all()) {
  const d = item.json;

  // Extract key identifiers
  const businessName = d.title || d.name || 'Unknown Business';
  const placeId = d.url || d.placeId || `${businessName}-${Date.now()}`;
  const searchString = d.searchString || d.search || '';

  // Build comprehensive business_data JSONB object
  const businessData = {
    // Overview dimension
    overview: {
      title: d.title,
      category: d.categoryName || d.category,
      address: d.address,
      city: d.city,
      state: d.state,
      zip: d.zip,
      country: d.country || 'USA',
      location: d.location,
      latitude: d.location?.lat,
      longitude: d.location?.lng,
      url: d.url,
      searchString: searchString
    },

    // Contact dimension
    contact: {
      phone: d.phone || d.phoneNumber,
      website: d.website,
      email: d.email,
      addressComponents: d.addressComponents
    },

    // Social dimension
    social: {
      instagrams: d.instagrams,
      facebooks: d.facebooks,
      twitters: d.twitters,
      linkedins: d.linkedins,
      youtubes: d.youtubes,
      social_media: d.social_media
    },

    // Rating dimension
    rating: {
      totalScore: d.totalScore,
      reviewsCount: d.reviewsCount,
      rating: d.rating,
      reviews_count: d.reviews?.length || 0
    },

    // Popular times dimension
    popular_times: {
      popularTimesHistogram: d.popularTimesHistogram,
      openingHours: d.openingHours,
      peopleAlsoSearch: d.peopleAlsoSearch
    },

    // Tags dimension
    tags: {
      additionalInfo: d.additionalInfo,
      placesTags: d.placesTags,
      categoryTags: d.categoryTags
    },

    // Lead enrichment dimension
    lead_enrichment: {
      claimedBy: d.claimedBy,
      verificationDetails: d.verificationDetails,
      temporarilyClosed: d.temporarilyClosed,
      permanentlyClosed: d.permanentlyClosed
    },

    // Metadata
    scraped_at: new Date().toISOString(),
    apify_place_id: placeId
  };

  results.push({
    json: {
      execution_id: executionId,
      business_name: businessName,
      search_string: searchString,
      apify_place_id: placeId,
      business_data: businessData
    }
  });
}

return results;

// Prepare Reviews for Postgres Batch Insert
// Flattens reviews from Apify data and links to business_id from Upsert node

const results = [];

// Get original Apify data (before transformation)
const apifyData = $('Fetch Apify Data').all();

// Get business records just inserted/updated
const businesses = $('Upsert Business').all();

// Create lookup map: apify_place_id -> business database id
const businessIdMap = new Map();
for (const biz of businesses) {
  const placeId = biz.json.apify_place_id;
  const dbId = biz.json.id;
  if (placeId && dbId) {
    businessIdMap.set(placeId, dbId);
  }
}

// Process each place from Apify data
for (const place of apifyData) {
  const p = place.json;

  // Get business_id from our map
  const placeId = p.url || p.placeId;
  const businessId = businessIdMap.get(placeId);

  if (!businessId) {
    console.log(`Warning: No business_id found for ${p.title} (${placeId})`);
    continue;
  }

  // Check if reviews exist
  if (!Array.isArray(p.reviews) || p.reviews.length === 0) {
    console.log(`No reviews for ${p.title}`);
    continue;
  }

  // Flatten all reviews for this business
  for (const review of p.reviews) {
    results.push({
      json: {
        business_id: businessId,
        review_data: JSON.stringify({
          // Business context
          placeName: p.title,
          placeId: placeId,

          // Reviewer info
          reviewerId: review.reviewerId,
          reviewerUrl: review.reviewerUrl,
          reviewerName: review.name,
          reviewerNumberOfReviews: review.reviewerNumberOfReviews,
          reviewerProfilePhotoUrl: review.profilePhotoUrl,
          isLocalGuide: review.isLocalGuide,

          // Review content
          stars: review.stars,
          text: review.text,
          textTranslated: review.textTranslated,

          // Metadata
          publishAt: review.publishAt,
          publishedAtDate: review.publishedAtDate,
          likesCount: review.likesCount,

          // Review identifiers
          reviewId: review.reviewId,
          reviewUrl: review.reviewUrl,

          // Media
          reviewImageUrls: review.reviewImageUrls,
          reviewImageUrl: review.reviewImageUrl,

          // Owner response
          responseFromOwnerDate: review.responseFromOwnerDate,
          responseFromOwnerText: review.responseFromOwnerText,
          responseFromOwnerAgo: review.responseFromOwnerAgo
        })
      }
    });
  }
}

console.log(`Prepared ${results.length} reviews for ${businessIdMap.size} businesses`);
return results;
